export const docsGuide: DocsGuide = {"categories":[{"title":"Getting started","stories":[{"id":"sign-in","title":"Sign in to Coder","introHtml":"<p>Coder is where a software project lives: its vision, the repos it touches, its team and its user stories. Like every OpenApe app you sign in with your email domain and a passkey — no new account, no password.</p>\n","steps":[{"title":"Open Coder","html":"The start page is the sign-in: enter your email and continue.","shot":"/docs/screenshots/sign-in/01-landing.png"},{"title":"Signed in — your projects","html":"On your first visit the list is empty. You only ever see projects you belong to — nobody outside a project can tell it, or its people, exist.","shot":"/docs/screenshots/sign-in/02-home-empty.png"}]}]},{"title":"Projects","stories":[{"id":"create-project","title":"Create a project","introHtml":"<p>A project is the home for one software effort. You create it, become its admin, and give it a vision and the repos it touches — the shared context everyone on the team reads.</p>\n","steps":[{"title":"Start a new project","html":"Click <strong>New project</strong> and name it. As its creator you become the project admin.","shot":"/docs/screenshots/create-project/01-dialog.png"},{"title":"Name it","html":"The project page opens: an overview with its vision and repos, a members panel, and the story board.","shot":"/docs/screenshots/create-project/02-project-page.png"},{"title":"Vision and repos","html":"The vision is plain prose; the repos are full URLs to the code it touches — GitHub, GitLab, Forgejo or self-hosted, never just <code>owner/repo</code>. Both stay editable as the project grows.","shot":"/docs/screenshots/create-project/03-scope-saved.png"}]}]},{"title":"Stories","stories":[{"id":"add-story","title":"Add a user story","introHtml":"<p>User stories live in the project, where everyone can see them — not in mail threads. A story has the usual parts and can carry repos, links, test references and a status.</p>\n","steps":[{"title":"Open the story board","html":"The board shows every story in the project at a glance. It is empty for a new project.","shot":"/docs/screenshots/add-story/01-board-empty.png"},{"title":"Write the story","html":"Give it a title and the story sentence — <em>As … I want … so that …</em>. The optional repos, links and test references can be added afterwards.","shot":"/docs/screenshots/add-story/02-story-dialog.png"},{"title":"Story created","html":"The story opens, laid out for reading — sentence, criteria and any references — no files or code to open.","shot":"/docs/screenshots/add-story/03-story-detail.png"}]},{"id":"story-board","title":"Browse the board","introHtml":"<p>Back on the board, every story shows its status. Group or filter to see exactly where the project stands.</p>\n","steps":[{"title":"All stories with status","html":"Each story carries a status badge. The board groups them so you read the project state in one look.","shot":"/docs/screenshots/story-board/01-board.png"}]}]},{"title":"Team","stories":[{"id":"invite-members","title":"Invite the team","introHtml":"<p>A project admin adds people by email and controls, per member, what they may do. No email is sent — a new member is added read-only and sees it in their inbox at the next sign-in. Every write capability is granted explicitly.</p>\n","steps":[{"title":"Open the members panel","html":"The Members panel lists who belongs to the project and their role.","shot":"/docs/screenshots/invite-members/01-members.png"},{"title":"Add by email","html":"Add a person by email address. The app never reveals whether that address already has an OpenApe identity — and only a human admin, never an agent, can do it.","shot":"/docs/screenshots/invite-members/02-invite-dialog.png"},{"title":"They'll see it in their inbox","html":"No email is sent: the new member is added as read-only and learns of it from an inbox notification the next time they sign in. The optional button drafts a heads-up in your own mail client — nothing leaves through our server.","shot":"/docs/screenshots/invite-members/03-member-added.png"}]}]}]}
